import React,{useState} from "react";
import axios from "axios";
export default function(){
const[s,set]=useState({});
function sub(){
axios.post("http://localhost:5000/student/add",s).then(()=>alert("Added"));
}
return(<div className="box">
<h2>Student Form</h2>
<input placeholder="Roll" onChange={e=>set({...s,roll:e.target.value})}/>
<input placeholder="Name" onChange={e=>set({...s,name:e.target.value})}/>
<input placeholder="CGPA" onChange={e=>set({...s,cgpa:e.target.value})}/>
<input placeholder="Attendance" onChange={e=>set({...s,att:e.target.value})}/>
<input placeholder="C" onChange={e=>set({...s,c:e.target.value})}/>
<input placeholder="Java" onChange={e=>set({...s,java:e.target.value})}/>
<input placeholder="Python" onChange={e=>set({...s,python:e.target.value})}/>
<button onClick={sub}>Submit</button>
</div>);}
